import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"戒台寺","description":"","frontmatter":{},"headers":[],"relativePath":"religion/jietai.md","filePath":"religion/jietai.md","lastUpdated":null}'),n={name:"religion/jietai.md"};function o(i,t,d,h,s,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="戒台寺" tabindex="-1">戒台寺 <a class="header-anchor" href="#戒台寺" aria-label="Permalink to &quot;戒台寺&quot;">​</a></h1><blockquote><p>&quot;中国三大戒台之一，松树与戒台闻名。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>戒台寺位于北京市门头沟区，与潭柘寺相距约10公里。戒台寺始建于唐武德五年（622年），是中国三大戒台之一（北京戒台寺、浙江杭州昭庆寺、福建泉州开元寺），以戒台、松、牡丹闻名。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">45元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春季牡丹，秋季松树</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线苹果园站转公交931路</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市门头沟区永定镇马鞍山</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>戒台寺始建于唐武德五年（622年），原名慧聚寺，是僧人修行的场所。</p><h3 id="辽代戒台" tabindex="-1">辽代戒台 <a class="header-anchor" href="#辽代戒台" aria-label="Permalink to &quot;辽代戒台&quot;">​</a></h3><p>辽咸雍五年（1069年），辽代高僧法均在此建戒坛，为僧人授戒，从此改名&quot;戒台寺&quot;。</p><h3 id="发展" tabindex="-1">发展 <a class="header-anchor" href="#发展" aria-label="Permalink to &quot;发展&quot;">​</a></h3><ul><li><strong>明代</strong>：明英宗赐名&quot;万寿禅寺&quot;</li><li><strong>清代</strong>：康熙、乾隆多次到此进香</li><li><strong>近代</strong>：民国时期逐渐衰落</li><li><strong>现代</strong>：1980年代修复后对外开放</li></ul><h2 id="三大特色" tabindex="-1">三大特色 <a class="header-anchor" href="#三大特色" aria-label="Permalink to &quot;三大特色&quot;">​</a></h2><p>戒台寺以&quot;戒台、松、牡丹&quot;三大特色闻名。</p><h3 id="戒台" tabindex="-1">戒台 <a class="header-anchor" href="#戒台" aria-label="Permalink to &quot;戒台&quot;">​</a></h3><p>戒台是戒台寺的核心，是中国三大戒台之一。</p><h4 id="戒台结构" tabindex="-1">戒台结构 <a class="header-anchor" href="#戒台结构" aria-label="Permalink to &quot;戒台结构&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>戒台高</strong></td><td style="text-align:left;">3.5米</td></tr><tr><td style="text-align:left;">:---</td><td style="text-align:left;">:---</td></tr><tr><td style="text-align:left;"><strong>戒台底面积</strong></td><td style="text-align:left;">约300平方米</td></tr><tr><td style="text-align:left;"><strong>戒台层数</strong></td><td style="text-align:left;">三层</td></tr><tr><td style="text-align:left;"><strong>戒座</strong></td><td style="text-align:left;">113个</td></tr></tbody></table><h4 id="戒座" tabindex="-1">戒座 <a class="header-anchor" href="#戒座" aria-label="Permalink to &quot;戒座&quot;">​</a></h4><p>戒台上设有113个戒座，供僧人受戒时坐。戒座雕刻精美，是辽代石刻艺术的精品。</p><h4 id="受戒" tabindex="-1">受戒 <a class="header-anchor" href="#受戒" aria-label="Permalink to &quot;受戒&quot;">​</a></h4><p>受戒是佛教徒成为正式僧人的仪式。在戒台上受戒，是佛教界的最高荣誉。</p><h3 id="松树" tabindex="-1">松树 <a class="header-anchor" href="#松树" aria-label="Permalink to &quot;松树&quot;">​</a></h3><p>戒台寺以松树闻名，有&quot;潭柘以泉胜，戒台以松名&quot;之说。</p><h4 id="名松" tabindex="-1">名松 <a class="header-anchor" href="#名松" aria-label="Permalink to &quot;名松&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">松树</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>九龙松</strong></td><td style="text-align:left;">九条枝干，如九龙腾飞</td></tr><tr><td style="text-align:left;"><strong>抱塔松</strong></td><td style="text-align:left;">抱住古塔而生</td></tr><tr><td style="text-align:left;"><strong>卧龙松</strong></td><td style="text-align:left;">横卧如龙</td></tr><tr><td style="text-align:left;"><strong>活动松</strong></td><td style="text-align:left;">枝条可动</td></tr></tbody></table><h4 id="九龙松" tabindex="-1">九龙松 <a class="header-anchor" href="#九龙松" aria-label="Permalink to &quot;九龙松&quot;">​</a></h4><p>九龙松是戒台寺的镇寺之宝，植于辽代，距今已有千年历史。松树高20余米，九条主干，如九条巨龙腾飞。</p><h3 id="牡丹" tabindex="-1">牡丹 <a class="header-anchor" href="#牡丹" aria-label="Permalink to &quot;牡丹&quot;">​</a></h3><p>戒台寺种植了大量牡丹，每年春季牡丹盛开。</p><h4 id="牡丹品种" tabindex="-1">牡丹品种 <a class="header-anchor" href="#牡丹品种" aria-label="Permalink to &quot;牡丹品种&quot;">​</a></h4><p>戒台寺种植了各种牡丹，有&quot;洛阳牡丹&quot;&quot;菏泽牡丹&quot;等名贵品种。</p><h4 id="牡丹节" tabindex="-1">牡丹节 <a class="header-anchor" href="#牡丹节" aria-label="Permalink to &quot;牡丹节&quot;">​</a></h4><p>每年春季举办牡丹节，吸引大量游客。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是戒台寺的入口。</p><h3 id="天王殿" tabindex="-1">天王殿 <a class="header-anchor" href="#天王殿" aria-label="Permalink to &quot;天王殿&quot;">​</a></h3><p>天王殿供奉弥勒佛和四大天王。</p><h3 id="大雄宝殿" tabindex="-1">大雄宝殿 <a class="header-anchor" href="#大雄宝殿" aria-label="Permalink to &quot;大雄宝殿&quot;">​</a></h3><p>大雄宝殿是戒台寺的主殿。</p><h3 id="戒坛殿" tabindex="-1">戒坛殿 <a class="header-anchor" href="#戒坛殿" aria-label="Permalink to &quot;戒坛殿&quot;">​</a></h3><p>戒坛殿是供奉戒台的地方，是戒台寺的核心建筑。</p><h3 id="千佛阁" tabindex="-1">千佛阁 <a class="header-anchor" href="#千佛阁" aria-label="Permalink to &quot;千佛阁&quot;">​</a></h3><p>千佛阁供奉千佛，是戒台寺的重要建筑。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>山门 → 天王殿 → 大雄宝殿 → 戒坛殿（重点） → 千佛阁 → 名松（九龙松等） → 牡丹园 → 出寺</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;">公交</td><td style="text-align:left;">地铁1号线苹果园站 → 931路 → 戒台寺</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">莲石路 → 108国道 → 戒台寺</td></tr><tr><td style="text-align:left;">旅游专线</td><td style="text-align:left;">前门有旅游专线</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票较贵</strong>：门票45元</li><li><strong>戒台必看</strong>：戒台是精华，必看</li><li><strong>九龙松必看</strong>：九龙松是镇寺之宝</li><li><strong>春季牡丹</strong>：春季牡丹盛开</li><li><strong>结合游览</strong>：可与潭柘寺一起游览</li><li><strong>爬山</strong>：寺庙依山而建，需要爬山</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">潭柘寺</td><td style="text-align:center;">约10公里</td><td style="text-align:left;">北京最古老寺院</td></tr><tr><td style="text-align:left;">定都峰</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">俯瞰北京城</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>戒台寺是中国三大戒台之一，在佛教界地位崇高。</p><p>戒台寺的戒台是辽代建筑，是研究辽代建筑和佛教文化的重要实物资料。</p><p>戒台寺的名松是北京著名的古树名木，具有很高的观赏价值和科研价值。</p><hr><p><strong>📍 地址</strong>：北京市门头沟区永定镇马鞍山 <strong>📞 电话</strong>：010-69806611</p>',62)])])}const b=a(n,[["render",o]]);export{f as __pageData,b as default};
